sql:
SELECT COUNT(*) AS total_patients_with_diabetes
FROM chronic_conditions
WHERE condition_name = 'Diabetes';

SELECT county_name
FROM counties
WHERE population > 100000;

SELECT COUNT(patient_id) AS number_of_patients_with_chronic_conditions
FROM chronic_conditions
WHERE chronic_condition = 'Yes';

external_knowledge:
- 'Wealthier counties' refers to those with an average median income higher than the overall average income across all counties;
- 'Currently being treated' means the treatment status is 'In Treatment';
- 'Most recent check-up dates' means sorting by the last evaluation date in descending order.

- "Swimming in the current of prosperity" is a metaphor for having a high median income;
- "Median incomes flowing above the $50,000 river" refers to median incomes greater than $50,000;
- "River's depth" is a metaphor for the amount of median income, indicating the difference in income levels between different counties;
- "Deepest to the shallowest waters" means sorting counties from highest to lowest median incomes.

sql:
SELECT COUNT(cc.patient_id) AS patient_count
FROM chronic_conditions cc
WHERE cc.chronic_condition = 'Yes' AND cc.condition_name = 'Diabetes';

SELECT 
    (SELECT AVG(age) FROM patients WHERE patient_id IN (SELECT patient_id FROM chronic_conditions)) AS avg_age_with_conditions,
    (SELECT AVG(age) FROM patients) AS avg_age_all_patients;
